mapper.select:
SELECT A.SSVC_LINE_TYPE_CD , A.SSVC_GROUP_CD , A.SSVC_OBJ_CD , A.SSVC_LINE_TYPE_NM SSVC_LINE_TYPE_NM , A.SSVC_GROUP_NM , A.SSVC_OBJ_NM , A.NWIRE_IP_COMMU_SEQ , A.SKIND_CD , A.SCOMMUNITY , A.SNEXTHOP , A.NLVL_BAS_SEQ , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID , A.RNUM FROM ( SELECT A.SSVC_LINE_TYPE_CD , A.SSVC_GROUP_CD , A.SSVC_OBJ_CD , A.SSVC_LINE_TYPE_NM SSVC_LINE_TYPE_NM , A.SSVC_GROUP_NM , A.SSVC_OBJ_NM , A.NWIRE_IP_COMMU_SEQ , A.SKIND_CD , A.SCOMMUNITY , A.SNEXTHOP , A.NLVL_BAS_SEQ , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID , ROWNUM RNUM FROM ( SELECT CASE WHEN A.skind_cd = 'KORNET' THEN B.SSVC_LINE_TYPE_CD ELSE C.SSVC_LINE_TYPE_CD END SSVC_LINE_TYPE_CD , CASE WHEN A.skind_cd = 'KORNET' THEN B.SSVC_LINE_TYPE_NM ELSE C.SSVC_LINE_TYPE_NM END SSVC_LINE_TYPE_NM , CASE WHEN A.skind_cd = 'KORNET' THEN B.SSVC_GROUP_CD ELSE C.SSVC_GROUP_CD END SSVC_GROUP_CD , CASE WHEN A.skind_cd = 'KORNET' THEN B.SSVC_GROUP_NM ELSE C.SSVC_GROUP_NM END SSVC_GROUP_NM , CASE WHEN A.skind_cd = 'KORNET' THEN B.SSVC_OBJ_CD ELSE C.SSVC_OBJ_CD END SSVC_OBJ_CD , CASE WHEN A.skind_cd = 'KORNET' THEN B.SSVC_OBJ_NM ELSE C.SSVC_OBJ_NM END SSVC_OBJ_NM , A.NWIRE_IP_COMMU_SEQ , A.SKIND_CD , A.SCOMMUNITY , A.SNEXTHOP , A.NLVL_BAS_SEQ , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID FROM MST.TB_WIRE_IP_COMMU_MST A, (SELECT A.NLVL_BAS_SEQ , A.SSVC_LINE_TYPE_CD , D.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD , B.SLVL_NM AS SSVC_GROUP_NM , A.SSVC_OBJ_CD , C.SLVL_NM AS SSVC_OBJ_NM FROM MST.TB_LVL_BAS A , MST.TB_LVL_CD B , MST.TB_LVL_CD C , MST.TB_SVC_LINE_TYPE_CD D WHERE 1=1 AND A.SSVC_LINE_TYPE_CD = 'CL0001' AND A.SSVC_GROUP_CD = B.SLVL_CD AND A.SSVC_OBJ_CD = C.SLVL_CD AND A.SSVC_LINE_TYPE_CD = D.SSVC_LINE_TYPE_CD) B, (SELECT A.NLVL_MST_SEQ , A.SSVC_LINE_TYPE_CD , D.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD , B.SLVL_NM AS SSVC_GROUP_NM , A.SSVC_OBJ_CD , C.SLVL_NM AS SSVC_OBJ_NM FROM MST.TB_LVL_MST A , MST.TB_LVL_CD B , MST.TB_LVL_CD C , MST.TB_SVC_LINE_TYPE_CD D WHERE 1=1 AND A.SSVC_LINE_TYPE_CD = 'CL0002' AND A.SSVC_GROUP_CD = B.SLVL_CD AND A.SSVC_OBJ_CD = C.SLVL_CD AND A.SSVC_LINE_TYPE_CD = D.SSVC_LINE_TYPE_CD ) C WHERE 1=1 AND A.NLVL_BAS_SEQ = B.NLVL_BAS_SEQ(+) AND A.NLVL_BAS_SEQ = C.NLVL_MST_SEQ(+)
AND A.SKIND_CD = #{skindCd, jdbcType=VARCHAR}
AND A.SCOMMUNITY ILIKE '%' || #{scommunity, jdbcType=VARCHAR} || '%'
AND A.SNEXTHOP ILIKE '%' || #{snexthop, jdbcType=VARCHAR} || '%'
) A WHERE ROWNUM <= #{lastIndex} ) A WHERE RNUM >= #{firstIndex}

SELECT count(1) totalCount FROM ( SELECT CASE WHEN A.skind_cd = 'KORNET' THEN B.SSVC_LINE_TYPE_CD ELSE C.SSVC_LINE_TYPE_CD END SSVC_LINE_TYPE_CD , CASE WHEN A.skind_cd = 'KORNET' THEN B.SSVC_LINE_TYPE_NM ELSE C.SSVC_LINE_TYPE_NM END SSVC_LINE_TYPE_NM , CASE WHEN A.skind_cd = 'KORNET' THEN B.SSVC_GROUP_CD ELSE C.SSVC_GROUP_CD END SSVC_GROUP_CD , CASE WHEN A.skind_cd = 'KORNET' THEN B.SSVC_GROUP_NM ELSE C.SSVC_GROUP_NM END SSVC_GROUP_NM , CASE WHEN A.skind_cd = 'KORNET' THEN B.SSVC_OBJ_CD ELSE C.SSVC_OBJ_CD END SSVC_OBJ_CD , CASE WHEN A.skind_cd = 'KORNET' THEN B.SSVC_OBJ_NM ELSE C.SSVC_OBJ_NM END SSVC_OBJ_NM , A.NWIRE_IP_COMMU_SEQ , A.SKIND_CD , A.SCOMMUNITY , A.SNEXTHOP , A.NLVL_BAS_SEQ , A.DCREATE_DT , A.SCREATE_ID , A.DMODIFY_DT , A.SMODIFY_ID FROM MST.TB_WIRE_IP_COMMU_MST A, (SELECT A.NLVL_BAS_SEQ , A.SSVC_LINE_TYPE_CD , D.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD , B.SLVL_NM AS SSVC_GROUP_NM , A.SSVC_OBJ_CD , C.SLVL_NM AS SSVC_OBJ_NM FROM MST.TB_LVL_BAS A , MST.TB_LVL_CD B , MST.TB_LVL_CD C , MST.TB_SVC_LINE_TYPE_CD D WHERE 1=1 AND A.SSVC_LINE_TYPE_CD = 'CL0001' AND A.SSVC_GROUP_CD = B.SLVL_CD AND A.SSVC_OBJ_CD = C.SLVL_CD AND A.SSVC_LINE_TYPE_CD = D.SSVC_LINE_TYPE_CD) B, (SELECT A.NLVL_MST_SEQ , A.SSVC_LINE_TYPE_CD , D.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD , B.SLVL_NM AS SSVC_GROUP_NM , A.SSVC_OBJ_CD , C.SLVL_NM AS SSVC_OBJ_NM FROM MST.TB_LVL_MST A , MST.TB_LVL_CD B , MST.TB_LVL_CD C , MST.TB_SVC_LINE_TYPE_CD D WHERE 1=1 AND A.SSVC_LINE_TYPE_CD = 'CL0002' AND A.SSVC_GROUP_CD = B.SLVL_CD AND A.SSVC_OBJ_CD = C.SLVL_CD AND A.SSVC_LINE_TYPE_CD = D.SSVC_LINE_TYPE_CD ) C WHERE 1=1 AND A.NLVL_BAS_SEQ = B.NLVL_BAS_SEQ(+) AND A.NLVL_BAS_SEQ = C.NLVL_MST_SEQ(+)
AND A.SKIND_CD = #{skindCd, jdbcType=VARCHAR}
AND A.SCOMMUNITY ILIKE '%' || #{scommunity, jdbcType=VARCHAR} || '%'
AND A.SNEXTHOP ILIKE '%' || #{snexthop, jdbcType=VARCHAR} || '%'
)

SELECT
	NLVL_MST_SEQ ,
	SSVC_LINE_TYPE_CD ,
	SSVC_GROUP_CD
FROM
	MST.TB_LVL_MST TLM
WHERE
	SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd,jdbcType=VARCHAR}
	AND SSVC_GROUP_CD = #{ssvcGroupCd,jdbcType=VARCHAR}
	AND SSVC_OBJ_CD = #{ssvcObjCd,jdbcType=VARCHAR}
